// form-builder.js
document.addEventListener("DOMContentLoaded", function() {
  var formFields = []; // Stores form field configuration

  // Add event listeners to the buttons
  document.getElementById("add-textfield").addEventListener("click", function() {
    addFormField("text");
  });

  document.getElementById("add-checkbox").addEventListener("click", function() {
    addFormField("checkbox");
  });

  document.getElementById("add-dropdown").addEventListener("click", function() {
    addFormField("dropdown");
  });

  document.getElementById("generate-form").addEventListener("click", function() {
    generateForm();
  });

  // Function to add form fields dynamically
  function addFormField(type) {
    var field = {
      type: type
    };

    formFields.push(field);

    var formFieldContainer = document.createElement("div");
    formFieldContainer.className = "form-field";

    if (type === "text") {
      formFieldContainer.innerHTML = `
        <label>Text Field:</label>
        <input type="text">
      `;
    } else if (type === "checkbox") {
      formFieldContainer.innerHTML = `
        <label>Checkbox:</label>
        <input type="checkbox">
      `;
    } else if (type === "dropdown") {
      formFieldContainer.innerHTML = `
        <label>Dropdown:</label>
        <select>
          <option value="option1">Option 1</option>
          <option value="option2">Option 2</option>
          <option value="option3">Option 3</option>
        </select>
      `;
    }

    document.getElementById("form-fields").appendChild(formFieldContainer);
  }

  // Function to generate the final form based on form field configuration
  function generateForm() {
    var formPreview = document.getElementById("form-preview");
    formPreview.innerHTML = "";

    formFields.forEach(function(field) {
      var formFieldPreview = document.createElement("div");

      if (field.type === "text") {
        formFieldPreview.innerHTML = `
          <label>Text Field:</label>
          <input type="text">
        `;
      } else if (field.type === "checkbox") {
        formFieldPreview.innerHTML = `
          <label>Checkbox:</label>
          <input type="checkbox">
        `;
      } else if (field.type === "dropdown") {
        formFieldPreview.innerHTML = `
          <label>Dropdown:</label>
          <select>
            <option value="option1">Option 1</option>
            <option value="option2">Option 2</option>
            <option value="option3">Option 3</option>
          </select>
        `;
      }

      formPreview.appendChild(formFieldPreview);
    });

    // Optionally, you can submit the generated form using AJAX or perform other actions.
  }
});
